import React, { useState, useEffect } from 'react';
import api from '../../api/axios';

const STATUSES = ['New Enquiry','Contacted','Counselling Scheduled','Document Submitted','Admitted','Rejected','Not Interested'];
const SOURCES  = ['Walk-in','Online','Agent','Friend','Social Media'];
const GENDERS  = ['Male','Female','Other'];
const DEFAULT_SUBJECTS = ['Tamil','English','Mathematics','Physics','Chemistry','Biology','Computer Science'];

export default function StudentFormModal({ student, onClose, onSaved }) {
  const [staff, setStaff]   = useState([]);
  const [saving, setSaving] = useState(false);
  const [error, setError]   = useState('');

  const emptyForm = () => ({
    name: '', email: '', phone: '', alt_phone: '',
    application_number: '', gender: '', aadhar_no: '',
    community: '', caste: '',
    status: 'New Enquiry', assigned_staff_id: '',
    twelfth_percentage: '', total_score: '', obtained_score: '',
    subject_marks: DEFAULT_SUBJECTS.map(s => ({ subject: s, max_mark: '', obtained_mark: '' })),
    counselling_date: '', applied_date: '', submitted_date: '',
    next_followup_date: '', lead_source: 'Walk-in', notes: '',
  });

  const [form, setForm] = useState(emptyForm);

  useEffect(() => {
    api.get('/users').then(r => setStaff(r.data)).catch(() => {});
  }, []);

  useEffect(() => {
    if (student) {
      setForm({
        name:               student.name || '',
        email:              student.email || '',
        phone:              student.phone || '',
        alt_phone:          student.alt_phone || '',
        application_number: student.application_number || '',
        gender:             student.gender || '',
        aadhar_no:          student.aadhar_no || '',
        community:          student.community || '',
        caste:              student.caste || '',
        status:             student.status || 'New Enquiry',
        assigned_staff_id:  student.assigned_staff_id?._id || student.assigned_staff_id || '',
        twelfth_percentage: student.twelfth_percentage ?? '',
        total_score:        student.total_score ?? '',
        obtained_score:     student.obtained_score ?? '',
        subject_marks:      Array.isArray(student.subject_marks) && student.subject_marks.length > 0
          ? student.subject_marks.map(s => ({ subject: s.subject || '', max_mark: s.max_mark ?? '', obtained_mark: s.obtained_mark ?? '' }))
          : DEFAULT_SUBJECTS.map(s => ({ subject: s, max_mark: '', obtained_mark: '' })),
        counselling_date:   student.counselling_date ? student.counselling_date.slice(0,10) : '',
        applied_date:       student.applied_date ? student.applied_date.slice(0,10) : '',
        submitted_date:     student.submitted_date ? student.submitted_date.slice(0,10) : '',
        next_followup_date: student.next_followup_date ? student.next_followup_date.slice(0,10) : '',
        lead_source:        student.lead_source || 'Walk-in',
        notes:              student.notes || '',
      });
    } else {
      setForm(emptyForm());
    }
  }, [student]);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const setMark = (i, k, v) => {
    const updated = [...form.subject_marks];
    updated[i] = { ...updated[i], [k]: v };
    setForm(f => ({ ...f, subject_marks: updated }));
  };

  const addSubject = () => setForm(f => ({
    ...f, subject_marks: [...f.subject_marks, { subject: '', max_mark: '', obtained_mark: '' }]
  }));

  const removeSubject = (i) => setForm(f => ({
    ...f, subject_marks: f.subject_marks.filter((_, idx) => idx !== i)
  }));

  const handleSubmit = async () => {
    if (!form.name || !form.email || !form.phone) {
      setError('Name, Email and Phone are required');
      return;
    }
    setSaving(true);
    setError('');
    try {
      const payload = {
        ...form,
        twelfth_percentage: form.twelfth_percentage !== '' ? form.twelfth_percentage : undefined,
        total_score:        form.total_score !== '' ? form.total_score : undefined,
        obtained_score:     form.obtained_score !== '' ? form.obtained_score : undefined,
        assigned_staff_id:  form.assigned_staff_id || null,
        subject_marks:      form.subject_marks.filter(s => s.subject.trim() !== ''),
      };
      if (student) await api.put(`/students/${student._id}`, payload);
      else         await api.post('/students', payload);
      onSaved();
    } catch (e) {
      setError(e.response?.data?.error || 'Failed to save student');
    } finally {
      setSaving(false);
    }
  };

  const F = ({ label, children, required }) => (
    <div style={{ display:'flex', flexDirection:'column', gap:4 }}>
      <label style={{ fontSize:11, fontWeight:600, color:'#64748b', textTransform:'uppercase', letterSpacing:'0.05em' }}>
        {label}{required && <span style={{ color:'#ef4444' }}> *</span>}
      </label>
      {children}
    </div>
  );

  const inp = (key, placeholder, type='text') => (
    <input type={type} placeholder={placeholder} value={form[key]}
      onChange={e => set(key, e.target.value)}
      style={{ padding:'9px 12px', border:'1.5px solid #e2e8f0', borderRadius:8, fontSize:14, outline:'none', width:'100%', boxSizing:'border-box' }} />
  );

  const sel = (key, options, placeholder='Select') => (
    <select value={form[key]} onChange={e => set(key, e.target.value)}
      style={{ padding:'9px 12px', border:'1.5px solid #e2e8f0', borderRadius:8, fontSize:14, outline:'none', width:'100%', background:'white', boxSizing:'border-box' }}>
      <option value=''>{placeholder}</option>
      {options.map(o => <option key={o} value={o}>{o}</option>)}
    </select>
  );

  const sectionTitle = (title) => (
    <div style={{ fontSize:12, fontWeight:700, color:'#0ea5e9', textTransform:'uppercase', letterSpacing:'0.08em', marginBottom:12, paddingBottom:6, borderBottom:'1.5px solid #e0f2fe' }}>
      {title}
    </div>
  );

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:1000, padding:16 }}>
      <div style={{ background:'white', borderRadius:16, width:'100%', maxWidth:800, maxHeight:'92vh', overflow:'hidden', display:'flex', flexDirection:'column', boxShadow:'0 24px 60px rgba(0,0,0,0.2)' }}>

        {/* Header */}
        <div style={{ padding:'20px 24px', borderBottom:'1px solid #e2e8f0', display:'flex', justifyContent:'space-between', alignItems:'center', flexShrink:0 }}>
          <h2 style={{ fontSize:18, fontWeight:700, margin:0 }}>{student ? 'Edit Student' : 'Add New Student'}</h2>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:20, cursor:'pointer', color:'#64748b' }}>✕</button>
        </div>

        {/* Body */}
        <div style={{ overflowY:'auto', padding:24, display:'flex', flexDirection:'column', gap:24 }}>
          {error && (
            <div style={{ background:'#fee2e2', color:'#dc2626', padding:'10px 14px', borderRadius:8, fontSize:13 }}>{error}</div>
          )}

          {/* Personal Info */}
          <div>
            {sectionTitle('Personal Information')}
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14 }}>
              <F label="Full Name" required>{inp('name','Student full name')}</F>
              <F label="Email" required>{inp('email','student@email.com','email')}</F>
              <F label="Phone" required>{inp('phone','10-digit mobile')}</F>
              <F label="Alternative Mobile">{inp('alt_phone','Alternative number')}</F>
              <F label="Gender">{sel('gender', GENDERS, 'Select gender')}</F>
              <F label="Application Number">{inp('application_number','Application number')}</F>
              <F label="Aadhar Number">{inp('aadhar_no','12-digit Aadhar number')}</F>
              <F label="Community">{inp('community','e.g. OBC, SC, ST, General')}</F>
              <F label="Caste">{inp('caste','Caste name')}</F>
              <F label="Lead Source">{sel('lead_source', SOURCES)}</F>
            </div>
          </div>

          {/* Academic Details */}
          <div>
            {sectionTitle('Academic Details')}
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:14, marginBottom:16 }}>
              <F label="12th Percentage">{inp('twelfth_percentage','e.g. 85.50','number')}</F>
              <F label="Total Score">{inp('total_score','Max total score','number')}</F>
              <F label="Obtained Score">{inp('obtained_score','Score obtained','number')}</F>
            </div>

            <div style={{ fontSize:11, fontWeight:600, color:'#64748b', textTransform:'uppercase', letterSpacing:'0.05em', marginBottom:8 }}>Subject Wise Marks</div>
            <div style={{ border:'1.5px solid #e2e8f0', borderRadius:10, overflow:'hidden' }}>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 130px 130px 40px', background:'#f8fafc', padding:'8px 12px', fontSize:11, fontWeight:700, color:'#64748b', textTransform:'uppercase' }}>
                <span>Subject</span><span>Max Mark</span><span>Obtained</span><span></span>
              </div>
              {form.subject_marks.map((sm, i) => (
                <div key={i} style={{ display:'grid', gridTemplateColumns:'1fr 130px 130px 40px', borderTop:'1px solid #e2e8f0', padding:'6px 12px', gap:8, alignItems:'center' }}>
                  <input value={sm.subject} onChange={e => setMark(i,'subject',e.target.value)} placeholder="Subject name"
                    style={{ padding:'6px 8px', border:'1px solid #e2e8f0', borderRadius:6, fontSize:13, width:'100%', boxSizing:'border-box' }} />
                  <input type="number" value={sm.max_mark} onChange={e => setMark(i,'max_mark',e.target.value)} placeholder="Max"
                    style={{ padding:'6px 8px', border:'1px solid #e2e8f0', borderRadius:6, fontSize:13, width:'100%', boxSizing:'border-box' }} />
                  <input type="number" value={sm.obtained_mark} onChange={e => setMark(i,'obtained_mark',e.target.value)} placeholder="Got"
                    style={{ padding:'6px 8px', border:'1px solid #e2e8f0', borderRadius:6, fontSize:13, width:'100%', boxSizing:'border-box' }} />
                  <button onClick={() => removeSubject(i)}
                    style={{ background:'none', border:'none', color:'#ef4444', cursor:'pointer', fontSize:16, padding:0 }}>✕</button>
                </div>
              ))}
              <div style={{ padding:'8px 12px', borderTop:'1px solid #e2e8f0' }}>
                <button onClick={addSubject}
                  style={{ background:'none', border:'none', color:'#0ea5e9', cursor:'pointer', fontSize:13, fontWeight:600, padding:0 }}>+ Add Subject</button>
              </div>
            </div>
          </div>

          {/* Admission Details */}
          <div>
            {sectionTitle('Admission Details')}
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14 }}>
              <F label="Status">{sel('status', STATUSES)}</F>
              <F label="Assigned Staff">
                <select value={form.assigned_staff_id} onChange={e => set('assigned_staff_id', e.target.value)}
                  style={{ padding:'9px 12px', border:'1.5px solid #e2e8f0', borderRadius:8, fontSize:14, outline:'none', width:'100%', background:'white', boxSizing:'border-box' }}>
                  <option value=''>Unassigned</option>
                  {staff.map(s => <option key={s._id} value={s._id}>{s.name}</option>)}
                </select>
              </F>
              <F label="Applied Date">{inp('applied_date','','date')}</F>
              <F label="Submitted Date">{inp('submitted_date','','date')}</F>
              <F label="Counselling Date">{inp('counselling_date','','date')}</F>
              <F label="Next Follow-up Date">{inp('next_followup_date','','date')}</F>
            </div>
          </div>

          {/* Notes */}
          <F label="Notes">
            <textarea value={form.notes} onChange={e => set('notes', e.target.value)} rows={3}
              placeholder="Any additional notes..."
              style={{ padding:'9px 12px', border:'1.5px solid #e2e8f0', borderRadius:8, fontSize:14, outline:'none', resize:'vertical', fontFamily:'inherit', width:'100%', boxSizing:'border-box' }} />
          </F>
        </div>

        {/* Footer */}
        <div style={{ padding:'16px 24px', borderTop:'1px solid #e2e8f0', display:'flex', justifyContent:'flex-end', gap:10, flexShrink:0 }}>
          <button onClick={onClose}
            style={{ padding:'9px 20px', border:'1.5px solid #e2e8f0', borderRadius:8, background:'white', cursor:'pointer', fontSize:14, fontWeight:600 }}>
            Cancel
          </button>
          <button onClick={handleSubmit} disabled={saving}
            style={{ padding:'9px 24px', background:'#0ea5e9', color:'white', border:'none', borderRadius:8, cursor:'pointer', fontSize:14, fontWeight:600, opacity: saving ? 0.7 : 1 }}>
            {saving ? 'Saving...' : 'Save Student'}
          </button>
        </div>

      </div>
    </div>
  );
}
